# schema.graphql — the source of truth for what the API can do.

type User {
  id: ID!
  name: String!
  email: String!
  orders(limit: Int = 10): [Order!]!
}

type Order {
  id: ID!
  total: Float!
  createdAt: String!
  items: [OrderItem!]!
}

type OrderItem {
  productId: ID!
  quantity: Int!
  unitPrice: Float!
}

type Query {
  user(id: ID!): User
  users(search: String, limit: Int = 20): [User!]!
}

type Mutation {
  createUser(input: CreateUserInput!): User!
  deleteUser(id: ID!): Boolean!
}

input CreateUserInput {
  name: String!
  email: String!
}

type Subscription {
  onNewOrder(userId: ID!): Order!
}

# The `!` means non-null. `[User!]!` = non-null list of non-null Users.
# GraphQL's null-safety > REST's silent-null-in-JSON convention.

# Client-side query. Ask for EXACTLY what you need — no more, no less.
query UserWithRecentOrders {
  user(id: "42") {
    id
    name
    orders(limit: 3) {
      id
      total
      items {
        productId
        quantity
      }
    }
  }
}

// Response matches the query shape EXACTLY. No over/under-fetching.
{
  "data": {
    "user": {
      "id": "42",
      "name": "Ada Lovelace",
      "orders": [
        { "id": "1001", "total": 42.50, "items": [{ "productId": "P1", "quantity": 2 }] },
        { "id": "1002", "total": 18.99, "items": [{ "productId": "P2", "quantity": 1 }] },
        { "id": "1003", "total": 89.00, "items": [{ "productId": "P3", "quantity": 3 }] }
      ]
    }
  }
}

// Node.js example (Apollo Server). Resolvers map each schema field to code.
const resolvers = {
  Query: {
    user: async (_, { id }, { db }) => db.user.findById(id),
    users: async (_, { search, limit }, { db }) => db.user.find({ search, limit }),
  },

  User: {
    // GraphQL resolver signature: (parentObject, args, context, info) => value
    orders: async (user, { limit }, { db }) =>
      db.order.findByUserId(user.id, { limit }),
  },

  Order: {
    items: async (order, _, { db }) => db.orderItem.findByOrderId(order.id),
  },

  Mutation: {
    createUser: async (_, { input }, { db }) => db.user.create(input),
    deleteUser: async (_, { id }, { db }) => { await db.user.delete(id); return true; },
  },

  Subscription: {
    onNewOrder: {
      subscribe: (_, { userId }, { pubsub }) => pubsub.asyncIterator(`ORDER_${userId}`),
    },
  },
};

// When a client asks for `user(42).orders(3).items`:
//   1. Query.user runs → returns user record.
//   2. User.orders runs with parent = that user.
//   3. For each order, Order.items runs with parent = that order.
//
// This is the N+1 problem: 1 query for user, 1 for orders, then N queries for items.
// Solution: DataLoader (see below).

// Without DataLoader — 1 orders query + N item queries.
// With DataLoader — 1 orders query + 1 items query total. Massive speedup.

import DataLoader from 'dataloader';

// Create per-request loaders in the GraphQL context.
function createContext({ db }) {
  return {
    db,
    itemsByOrderId: new DataLoader(async (orderIds) => {
      const items = await db.orderItem.findByOrderIdsIn(orderIds);
      // Group by orderId, return arrays in same order as input
      const byOrder = new Map(orderIds.map((id) => [id, []]));
      for (const item of items) byOrder.get(item.orderId).push(item);
      return orderIds.map((id) => byOrder.get(id));
    }),
  };
}

// Resolver uses the loader instead of raw DB call.
const resolvers = {
  Order: {
    items: (order, _, { itemsByOrderId }) => itemsByOrderId.load(order.id),
  },
};

// DataLoader batches all .load(id) calls in one event-loop tick,
// dispatches ONE query, and distributes results back. Every serious
// GraphQL server uses it.
